// the class of the Server represents the functions of the server, this class can be have
// another name but is called Server in this script
class Server {
    // this is the init function necesary for the initialization of all the Server
    // uses the param of the api of the current server
    func init(ServerToInit) { 
        var carReferenceNew = ServerToInit.virtualWorkspace.importScene("/Assets/CarReference");
        var newGroup = ServerToInit.virtualWorkspace.addChild(Group(), "/", "MyCar");
        var MyCar = carReferenceNew.instantiate(newGroup);
        var baseOfCar = SerializableObject(MyCar.find("Car/Base"));
        baseOfCar.pos.set(Vector3(0,0,0));
        baseOfCar.update();
    }
    // this is the update function necesary for the update of the server
    // this functions executes each frame in the server context
    func update(ServerToUpdate) { }
}
// the class of the Client represents the functions of the client, this class can be have
// another name but is called Client in this script
class Client {
    // this is the init function necesary for the initialization of each player, this functions
    // is exectued for each player that joins on the server
    func conected(client,ServerToUpdate) { client.pass(client.box); }
    // this is the update function necesary for the update all the client
    // this functions executes each frame in a each client context
    func update(client,ServerToUpdate) {
    }
}
// conects all the server and client with the exports api, this class needs to have this exactly name
// for be exported and considerated
class serverOrLocalService {
    var sInit = Server.init;
    var sUpdate = Server.update;
    var cConected = Client.conected;
    var cUpdate = Client.update;
}
